        int n = online.length;
        List<List<int[]>> graph = new ArrayList<>();
        for (int i = 0; i < n; i++) {
            graph.add(new ArrayList<>());
        }

        for (long[] edge : edges) {
            int u = (int) edge[0];
            int v = (int) edge[1];
            int cost = (int) edge[2];
            if (online[u] && online[v]) {
                graph.get(u).add(new int[] {v, cost});
            }
        }

        // Use Dijkstra's algorithm to find the maximum minimum edge cost
        // We prioritize paths with higher minimum edge cost
        PriorityQueue<int[]> pq = new PriorityQueue<>((a, b) -> {
            return Long.compare(b[2], a[2]);
        });

        pq.offer(new int[] {0, 0, Integer.MAX_VALUE}); // (node, current_min_edge_cost, total_cost)

