            int node = current[0];
            long current_min = current[1];
            long total_cost = current[2];

            if (node == n - 1) {
                return current_min;
            }

            for (int[] neighbor : graph.get(node)) {
                int v = neighbor[0];
                int cost = neighbor[1];

                if (online[v] && !visited[v]) {
                    long new_total_cost = total_cost + cost;
                    if (new_total_cost <= k) {
