import java.util.*;

public class Solution {
    public static long solve(long[][] edges, boolean[] online, long k) {
        int n = online.length;
        Map<Integer, List<Edge>> graph = new HashMap<>();

        for (long[] edge : edges) {
            int u = (int) edge[0];
            int v = (int) edge[1];
            long cost = (long) edge[2];
            if (!graph.containsKey(u)) {
                graph.put(u, new ArrayList<>());
            }
            graph.get(u).add(new Edge(v, cost));
        }

        // Use Dijkstra's algorithm with a priority queue to find the maximum minimum edge cost
        PriorityQueue<State> pq = new PriorityQueue<>((a, b) -> Long.compare(b.minCost, a.minCost));
        pq.offer(new State(0, 0, Long.MAX_VALUE)); // (node, currentCost, minEdgeCost)

        boolean[] visited = new boolean[n];
        visited[0] = true;

        while (!pq.isEmpty()) {
            State current = pq.poll();
            int node = current.node;
            long currentCost = current.currentCost;
            long minEdgeCost = current.minEdgeCost;

            if (node == n - 1) {
                return minEdgeCost;
            }

            if (currentCost > k) {
                continue;
            }

            if (visited[node]) {
                continue;
            }

            visited[node] = true;

            if (graph.containsKey(node)) {
                for (Edge edge : graph.get(node)) {
                    int neighbor = edge.v;
                    long cost = edge.cost;
                    long newCost = currentCost + cost;
                    long newMinEdgeCost = Math.min(minEdgeCost, cost);

                    if (online[neighbor] && newCost <= k) {
                        pq.offer(new State(neighbor, newCost, newMinEdgeCost));
                    }
                }
            }
        }

        return -1;
    }

    static class Edge {
        int v;
        long cost;
        Edge(int v, long cost) {
            this.v = v;
            this.cost = cost;
        }
    }

    static class State {
        int node;
        long currentCost;
        long minEdgeCost;
        State(int node, long currentCost, long minEdgeCost) {
            this.node = node;
            this.currentCost = currentCost;
            this.minEdgeCost = minEdgeCost;
        }
    }
}
